#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub enum Slant {
    Upright,
    Italic,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
pub struct FontStyle {
    pub weight: u16,
    pub width: u8,
    pub slant: Slant,
}

#[derive(Clone, Copy, Debug)]
pub struct FontMetrics {
    pub flags: u32,
    pub top: f32,
    pub ascent: f32,
    pub descent: f32,
    pub bottom: f32,
    pub leading: f32,
    pub average_char_width: f32,
    pub max_char_width: f32,
    pub x_min: f32,
    pub x_max: f32,
    pub x_height: f32,
    pub cap_height: f32,
    pub underline_thickness: f32,
    pub underline_position: f32,
    pub strikeout_thickness: f32,
    pub strikeout_position: f32,
}

#[derive(Clone, Copy, Debug)]
pub struct TestFontData {
    pub generic_family: &'static str,
    pub toy_family: &'static str,
    pub source_file: &'static str,
    pub style: FontStyle,
    pub points: &'static [f32],
    pub verbs: &'static [u8],
    pub char_codes: &'static [u32],
    pub advances: &'static [u32],
    pub metrics: FontMetrics,
}

#[derive(Clone, Copy, Debug)]
pub struct GlyphOutline {
    pub verbs: &'static [u8],
    pub points: &'static [f32],
}

impl TestFontData {
    pub fn glyph_index(&self, character: u32) -> Option<usize> {
        self.char_codes.iter().position(|&code| code == character)
    }

    pub fn advance_fixed(&self, glyph_index: usize) -> Option<u32> {
        self.advances.get(glyph_index).copied()
    }

    pub fn outline(&self, glyph_index: usize) -> Option<GlyphOutline> {
        let mut verb_start = 0;
        for _ in 0..glyph_index {
            let length = self
                .verbs
                .get(verb_start..)?
                .iter()
                .position(|&verb| verb == DONE_VERB)?
                + 1;
            verb_start += length;
        }
        let verb_end = verb_start
            + self
                .verbs
                .get(verb_start..)?
                .iter()
                .position(|&verb| verb == DONE_VERB)?;
        let point_start = self.verbs[..verb_start]
            .iter()
            .map(|&verb| point_count(verb))
            .sum::<usize>()
            * 2;
        let point_end = point_start
            + self.verbs[verb_start..verb_end]
                .iter()
                .map(|&verb| point_count(verb))
                .sum::<usize>()
                * 2;
        Some(GlyphOutline {
            verbs: &self.verbs[verb_start..verb_end],
            points: self.points.get(point_start..point_end)?,
        })
    }

    pub fn resolve_glyph(&self, character: u32) -> Option<GlyphOutline> {
        self.outline(self.glyph_index(character)?)
    }

    pub fn validate(&self) -> Result<(), &'static str> {
        if self.char_codes.len() != self.advances.len() || !self.points.len().is_multiple_of(2) {
            return Err("table lengths");
        }
        let _ = self.metrics.flags;
        if ![
            self.metrics.top,
            self.metrics.ascent,
            self.metrics.descent,
            self.metrics.bottom,
            self.metrics.leading,
            self.metrics.average_char_width,
            self.metrics.max_char_width,
            self.metrics.x_min,
            self.metrics.x_max,
            self.metrics.x_height,
            self.metrics.cap_height,
            self.metrics.underline_thickness,
            self.metrics.underline_position,
            self.metrics.strikeout_thickness,
            self.metrics.strikeout_position,
        ]
        .iter()
        .all(|value| value.is_finite())
        {
            return Err("non-finite metrics");
        }
        let mut glyphs = 0;
        let mut points = 0;
        for &verb in self.verbs {
            if verb > DONE_VERB {
                return Err("unknown path verb");
            }
            points += point_count(verb);
            if verb == DONE_VERB {
                glyphs += 1;
            }
        }
        if glyphs != self.char_codes.len() || points * 2 != self.points.len() {
            return Err("outline tables");
        }
        Ok(())
    }
}

pub const MOVE_VERB: u8 = 0;
pub const LINE_VERB: u8 = 1;
pub const QUAD_VERB: u8 = 2;
pub const CUBIC_VERB: u8 = 4;
pub const CLOSE_VERB: u8 = 5;
pub const DONE_VERB: u8 = 6;

const fn point_count(verb: u8) -> usize {
    match verb {
        MOVE_VERB | LINE_VERB => 1,
        QUAD_VERB => 2,
        CUBIC_VERB => 3,
        CLOSE_VERB | DONE_VERB => 0,
        _ => 0,
    }
}

