pub fn default_face() -> &'static TestFontData {
    &FACES[4]
}

pub fn resolve_face(family: &str, style: FontStyle) -> Option<&'static TestFontData> {
    FACES.iter().find(|face| {
        (face.generic_family == family || face.toy_family == family) && face.style == style
    })
}
